create table invoice_lines (
    invoice_line_id number generated by default as identity not null enable,
    invoice_id      varchar2(30 byte),
    source_order_id varchar2(30 byte),
    source_item_id  varchar2(30 byte),
    description     varchar2(1000 byte),
    quantity        number default 1,
    unit_price      number(12, 2),
    total_price     number(12, 2)
);

create unique index pk_invoice_lines on
    invoice_lines (
        invoice_line_id
    );

alter table invoice_lines
    add constraint pk_invoice_lines primary key ( invoice_line_id )
        using index pk_invoice_lines enable;

